USE LIVE
GO

SELECT * FROM [LIVESupplemental].[DBO].[ECIDUPDATES20210528]

SELECT *
FROM [LIVE].[dbo].[EC]
INNER JOIN [LIVESupplemental].[DBO].[ECIDUPDATES20210528] U
ON EC.ID = U.EC_ID

