SELECT *
FROM [LIVE].[dbo].[EC_GROUP_USER] E
INNER JOIN [LIVESupplemental].[DBO].[ECIDUPDATES20210528] U
ON E.EC_ID = U.EC_ID
WHERE USER_ID = 'CHARLEEN'

/*

UPDATE [EC_GROUP_USER]
SET [USER_ID] = 'CATHYO'
FROM [EC_GROUP_USER] E
INNER JOIN [LIVESupplemental].[DBO].[ECIDUPDATES20210528] U
ON E.EC_ID = U.EC_ID
WHERE USER_ID = 'CHARLEEN'
AND GROUP_TYPE = 'AT'
*/

SELECT *
FROM [LIVE].[dbo].[TASK] T
INNER JOIN [LIVESupplemental].[DBO].[ECIDUPDATES20210528] U
ON T.EC_ID = U.EC_ID
WHERE STATUS NOT IN ('C', 'X')

